import{_ as n,C as s,c as i,o as d,j as o,a1 as r,a as t,G as l}from"./chunks/framework.DDNAyvCW.js";const c="/assets/knowledgebase-interface-en.Pvekm0sN.png",m="/assets/add-to-chat.DCsLlCX2.mp4",h="/assets/summary-to-doc3.DLHpBugi.mp4",u="/assets/summary-to-doc4.rm_xq8EJ.mp4",p="/assets/data-sync.BQoxRxfH.png",C=JSON.parse('{"title":"Knowledge Base User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"docs/knowledgebase/index.md","filePath":"docs/knowledgebase/index.md"}'),g={name:"docs/knowledgebase/index.md"};function w(b,e,f,y,k,v){const a=s("KbDocIcon");return d(),i("div",null,[e[2]||(e[2]=o("h1",{id:"knowledge-base-user-guide",tabindex:"-1"},[t("Knowledge Base User Guide "),o("a",{class:"header-anchor",href:"#knowledge-base-user-guide","aria-label":'Permalink to "Knowledge Base User Guide"'},"​")],-1)),e[3]||(e[3]=o("p",null,"Notes are an indispensable way for every engineer to work and learn. In the past, we might store notes locally, in note-taking software, or in a company wiki system, and review or look them up when needed. But have you ever encountered this: because you switched note apps or devices, or simply because too much time has passed, you can no longer find those notes? In the era of AI-native applications, do we have a better way to write, manage, and use notes?",-1)),e[4]||(e[4]=o("p",null,'In AI-native application scenarios, a more ideal form of notes should satisfy two points: be tightly bound to the business application, and be usable for both humans and AI. Based on this, the Chaterm Knowledge Base provides a management approach where the "application itself is the carrier of knowledge": knowledge flows and accumulates along with the application, making it easier to maintain and reuse over the long term; at the same time, knowledge is organized in a structured form that models can directly consume, enabling AI to more stably understand user preferences, project constraints, and best practices, thereby improving collaboration efficiency and output consistency.',-1)),e[5]||(e[5]=o("p",null,"Practice has shown that in-context learning is one of the important ways to improve model consistency and reduce hallucinations. Persisting key information into the knowledge base in the form of files can serve as a high-quality context carrier. When executing tasks, the Agent can retrieve and read relevant content on demand, forming traceable and iterative context inputs.",-1)),e[6]||(e[6]=o("h2",{id:"edit-manage-files-in-chaterm",tabindex:"-1"},[t("Edit/Manage Files in Chaterm "),o("a",{class:"header-anchor",href:"#edit-manage-files-in-chaterm","aria-label":'Permalink to "Edit/Manage Files in Chaterm"'},"​")],-1)),o("p",null,[e[0]||(e[0]=t("Click the ",-1)),l(a),e[1]||(e[1]=t(" icon in the left sidebar to enter the knowledge base management interface. You can get a file management experience in Chaterm that is fully similar to VS Code. It supports creating new files/folders, renaming, moving, copying, pasting, deleting, and importing files/folders into the knowledge base.",-1))]),e[7]||(e[7]=r('<p>Chaterm uses VS Code&#39;s Monaco Editor as the built-in editor, with native support for Markdown/HTML/LaTeX/Mermaid and more, which better fits engineers&#39; writing habits.</p><p><img src="'+c+'" alt="Knowledge Base Interface"></p><h2 id="use-the-knowledge-base-as-conversation-context" tabindex="-1">Use the Knowledge Base as Conversation Context <a class="header-anchor" href="#use-the-knowledge-base-as-conversation-context" aria-label="Permalink to &quot;Use the Knowledge Base as Conversation Context&quot;">​</a></h2><p>You can attach documents in the knowledge base to AI messages, and the Agent will read them as context before making a request. Chaterm uses dynamic context technology and does not directly stuff the file contents into the conversation, thereby saving token usage.</p><h3 id="how-to-add-to-a-conversation" tabindex="-1">How to add to a conversation <a class="header-anchor" href="#how-to-add-to-a-conversation" aria-label="Permalink to &quot;How to add to a conversation&quot;">​</a></h3><p>There are multiple ways to add a file to the context:</p><ol><li>In the Knowledge Center, right-click and use <code>Add to chat</code> on the file</li><li>In the AI input box, type <strong><code>@</code></strong> to select a document.</li><li>Drag the opened file directly into the AI input box,</li></ol><p><video controls width="100%" src="'+m+'"></video></p><h2 id="command-custom-commands" tabindex="-1">/command (Custom Commands) <a class="header-anchor" href="#command-custom-commands" aria-label="Permalink to &quot;/command (Custom Commands)&quot;">​</a></h2><p><code>/command</code> is used to turn knowledge base files into reusable &quot;prompt snippets&quot; and quickly insert them into conversations.</p><p>Custom commands are stored as files under the knowledge base <code>commands/</code> directory.</p><h3 id="how-to-use" tabindex="-1">How to use: <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to use:&quot;">​</a></h3><ul><li>Type <strong><code>/</code></strong> in the AI input box to open the command selection popup.</li><li>After selecting, a <strong>command chip</strong> (command reference) will be inserted into the message.</li><li>Click this chip to open and edit the corresponding command file.</li></ul><h3 id="naming-recommendations" tabindex="-1">Naming recommendations: <a class="header-anchor" href="#naming-recommendations" aria-label="Permalink to &quot;Naming recommendations:&quot;">​</a></h3><ul><li>The command name is generated from the file name (without the extension) and automatically prefixed with <code>/</code>.</li><li>It is recommended to use <strong>kebab-case</strong> (for example, <code>deploy-guide.md</code> → <code>/deploy-guide</code>) to avoid input ambiguity caused by spaces.</li></ul><h2 id="summarize-to-the-knowledge-base" tabindex="-1">Summarize to the Knowledge Base <a class="header-anchor" href="#summarize-to-the-knowledge-base" aria-label="Permalink to &quot;Summarize to the Knowledge Base&quot;">​</a></h2><p>Chaterm provides a built-in command <code>/summary-to-doc</code>, which is used to write conversation summaries into the knowledge base.</p><h3 id="how-to-use-1" tabindex="-1">How to use: <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to &quot;How to use:&quot;">​</a></h3><ol><li>In the UI of each task completion message, there is a <code>Summarize to Knowledge Base</code> button. After clicking it, the model will call the <code>summarize_to_knowledge</code> tool and write the summary into the <code>summary</code> folder of the knowledge base in Markdown format.</li></ol><p><video controls width="100%" src="'+h+'" title="Title"></video></p><ol start="2"><li>With a custom command, type <code>/</code> in the input box and select the default <code>/summary-to-doc</code> command. If you have requirements for the summary format, you can modify the content of that command.</li></ol><p><video controls src="'+u+'" title="Title"></video></p><h2 id="knowledge-base-sync" tabindex="-1">Knowledge Base Sync <a class="header-anchor" href="#knowledge-base-sync" aria-label="Permalink to &quot;Knowledge Base Sync&quot;">​</a></h2><p>Chaterm can encrypt and sync your knowledge base to the cloud, and automatically keep it consistent across multiple devices under the same account. This includes regular documents, custom commands in <code>commands/</code>, summary notes in <code>summary/</code>, and imported assets such as images.</p><h3 id="how-to-use-2" tabindex="-1">How to use: <a class="header-anchor" href="#how-to-use-2" aria-label="Permalink to &quot;How to use:&quot;">​</a></h3><ol><li>Go to <code>Settings</code> --&gt; <code>Privacy</code> --&gt; <code>Data Sync</code>, turn on <code>Data Sync</code>, and make sure the device is signed in.</li></ol><p><img src="'+p+'" alt="Data Sync Setting"></p><ol start="2"><li>After you edit, import, or delete knowledge base content on any device, Chaterm syncs it automatically in the background, without manual upload or download.</li><li>Other signed-in devices with sync enabled will automatically pull the latest content, so you can continue using the same knowledge base across devices.</li></ol><p>Knowledge base sync is especially useful when switching to a new computer, moving between work and personal devices, or avoiding knowledge loss caused by local file issues.</p><h2 id="todo" tabindex="-1">TODO <a class="header-anchor" href="#todo" aria-label="Permalink to &quot;TODO&quot;">​</a></h2><p>We will soon support the following features:</p><ul><li><p>When starting each task, automatically retrieve the knowledge base to improve the accuracy of model responses, making your Chaterm better the more you use it.</p></li><li><p>Share the knowledge base within a team, so that all members use the same knowledge base.</p></li></ul>',32))])}const q=n(g,[["render",w]]);export{C as __pageData,q as default};
